def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def weather_impact_factor(customer_position):
        # Simplified model where farther customers have slower travel speeds due to potential poor weather
        distance_to_depot = calculate_distance(customer_position, depot_pos)
        if distance_to_depot > 10:
            return 0.9  # assume 10% slower speed for distant points
        return 1.0

    def adjusted_time_window_penalty(arrival_time, window):
        # Adjust penalties focusing more on arriving early
        start, end = window
        if arrival_time < start:
            return (start - arrival_time) * 10  # higher penalty for waiting
        elif arrival_time > end:
            return (arrival_time - end) * 50  # still a significant penalty for tardiness
        return 0

    best_node = None
    min_cost = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        base_travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        weather_factor = weather_impact_factor(customer_pos)
        adjusted_travel_time = base_travel_time / weather_factor
        arrival_time = current_time + adjusted_travel_time

        penalty = adjusted_time_window_penalty(arrival_time, time_windows[index])
        cost_from_depot = calculate_distance(customer_pos, depot_pos) # Minimizes distance to depot as a secondary priority
        total_cost = adjusted_travel_time + penalty + cost_from_depot * 0.1  # Weighted less to prioritize time and penalties

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = index

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    depot_proximity_factor = calculate_distance(cur_truck_pos, depot_pos)  # Factor considering distance to depot
    normalization_factor = np.mean([calculate_distance(cur_truck_pos, pos) for pos in unvisited_customers]) if unvisited_customers else 1

    best_node = None
    minimal_combined_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_distance = calculate_distance(cur_truck_pos, customer)
        travel_time = travel_distance / truck_speed
        arrive_time = current_time + travel_time
        tw_start, tw_end = time_windows[i]

        if arrive_time > tw_end:
            time_window_penalty = (arrive_time - tw_end) * 100  # High penalty for missing window
        elif arrive_time < tw_start:
            time_window_penalty = (tw_start - arrive_time) * 10  # Lower penalty for waiting
        else:
            time_window_penalty = 0

        # Calculating combined cost based on distance, time window penalty, and proximity to the depot
        combined_cost = (travel_distance / normalization_factor) + time_window_penalty + depot_proximity_factor

        if combined_cost < minimal_combined_cost:
            minimal_combined_cost = combined_cost
            best_node = i

    return best_node
